// MainActivity.java
import android.os.Bundle;
import android.util.Log;
import androidx.appcompat.app.AppCompatActivity;
import retrofit2.Call;
import retrofit2.Callback;
import retrofit2.Response;
import java.util.List;

public class MainActivity extends AppCompatActivity {
    private static final String TAG = "MainActivity";
    private static final String BASE_URL = getBaseUrl();
    
    @Override
    protected void onCreate(Bundle savedInstanceState) {
        super.onCreate(savedInstanceState);
        setContentView(R.layout.activity_main);
        
        fetchUsers();
    }
    
    private void fetchUsers() {
        ApiService apiService = NetworkClient.getClient(BASE_URL).create(ApiService.class);
        Call<List<User>> call = apiService.getUsers();
        call.enqueue(new Callback<List<User>>() {
            @Override
            public void onResponse(Call<List<User>> call, Response<List<User>> response) {
                if (response.isSuccessful() && response.body() != null) {
                    List<User> users = response.body();
                    Log.d(TAG, "Users fetched: " + users.size());
                    // Handle users data
                }
            }
            
            @Override
            public void onFailure(Call<List<User>> call, Throwable t) {
                Log.e(TAG, "Failed to fetch users", t);
            }
        });
    }
    
    private static String getBaseUrl() {
        // Environment configuration
        String environment = BuildConfig.ENVIRONMENT; // Set in build.gradle
        switch (environment) {
            case "staging":
                return "https://staging.api.example.com/";
            case "production":
                return "https://api.example.com/";
            default:
                return "https://dev.api.example.com/";
        }
    }
}